sys_script.script:
(function executeRule(current, previous) {

    var utils = new IncentNowAccessUtils();

    // =========================================
    // SYSTEM ADMIN / APPLICATION ADMIN
    // =========================================
    if (
        gs.getUser().hasRole('admin') ||
        gs.hasRole('x_ctans_incentnow.admin')
    ) {
        return;
    }

    // =========================================
    // BUSINESS GROUP EXECUTIVE
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.business_group_executive')) {

        utils.applyBusinessGroupExecutiveMetricReportFilter(current);
        return;
    }

    // =========================================
    // BUSINESS GROUP ADMIN
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.business_group_admin')) {

        utils.applyBusinessGroupAdminMetricReportFilter(current);
        return;
    }

    // =========================================
    // SALES MANAGER
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.manager')) {

        utils.applyManagerMetricReportFilter(current);
        return;
    }

    // =========================================
    // SALES REPRESENTATIVE
    // =========================================
    if (gs.hasRole('x_ctans_incentnow.user')) {

        utils.applySalesRepMetricReportFilter(current);
        return;
    }

})(current, previous);
